      out.write("    </style>\n");
      out.write("\n");
      out.write("    <script>\n");
      out.write("        /* ════════════════════════════════════════════════════════\n");
      out.write("           NAV SCRIPT — runs on every page\n");
      out.write("           Depends on VoyastraAuth (loaded in <head>)\n");
      out.write("        ════════════════════════════════════════════════════════ */\n");
      out.write("        document.addEventListener('DOMContentLoaded', function () {\n");
      out.write("\n");
      out.write("            /* ── Refs ──────────────────────────────────────────── */\n");
      out.write("            var menuBtn    = document.getElementById('mobileMenuBtn');\n");
      out.write("            var navLinks   = document.getElementById('navLinks');\n");
      out.write("            var navOverlay = document.getElementById('navOverlay');\n");
      out.write("            var widget     = document.getElementById('navAuthWidget');\n");
      out.write("            var dropdown   = null;   // created on demand\n");
      out.write("\n");
      out.write("            /* ── Mobile Sidebar (admin-panel style) ────────────── */\n");
      out.write("            function openMenu() {\n");
      out.write("                if (!navLinks) return;\n");
      out.write("                navLinks.classList.add('active');\n");
      out.write("                if (navOverlay) navOverlay.classList.add('active');\n");
      out.write("                document.body.style.overflow = 'hidden';\n");
      out.write("            }\n");
      out.write("            function closeMenu() {\n");
      out.write("                if (!navLinks) return;\n");
      out.write("                navLinks.classList.remove('active');\n");
      out.write("                if (navOverlay) navOverlay.classList.remove('active');\n");
      out.write("                document.body.style.overflow = '';\n");
      out.write("            }\n");
      out.write("            function toggleMenu() {\n");
      out.write("                navLinks.classList.contains('active') ? closeMenu() : openMenu();\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            if (menuBtn && navLinks) {\n");
      out.write("                menuBtn.addEventListener('click', toggleMenu);\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            /* Click outside (overlay) closes sidebar */\n");
      out.write("            if (navOverlay) navOverlay.addEventListener('click', closeMenu);\n");
      out.write("\n");
      out.write("            /* Close via sidebar ✕ button */\n");
      out.write("            var sidebarClose = document.getElementById('sidebarCloseBtn');\n");
      out.write("            if (sidebarClose) sidebarClose.addEventListener('click', closeMenu);\n");
      out.write("\n");
      out.write("            /* Close on any nav link click (auto-navigate) */\n");
      out.write("            if (navLinks) {\n");
      out.write("                navLinks.querySelectorAll('.nav-link').forEach(function(link) {\n");
      out.write("                    link.addEventListener('click', closeMenu);\n");
      out.write("                });\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            /* Close with Escape key */\n");
      out.write("            document.addEventListener('keydown', function(e) {\n");
      out.write("                if (e.key === 'Escape') closeMenu();\n");
      out.write("            });\n");
      out.write("\n");
      out.write("            /* ── Auth Widget Renderer ──────────────────────────── */\n");
      out.write("            function renderAuthWidget() {\n");
      out.write("                if (!widget) return;\n");
      out.write("                var session = VoyastraAuth.getSession();\n");
      out.write("                widget.innerHTML = '';\n");
      out.write("                dropdown = null;\n");
      out.write("\n");
      out.write("                if (!session) {\n");
      out.write("                    /* ── Logged OUT: show Login button ── */\n");
      out.write("                    var loginBtn = document.createElement('a');\n");
      out.write("                    loginBtn.href      = 'login'; // Go through Servlet\n");
      out.write("                    loginBtn.className = 'nav-login-btn';\n");
      out.write("                    loginBtn.innerHTML =\n");
      out.write("                        '<svg width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" stroke-linecap=\"round\"><path d=\"M15 3h4a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2h-4\"/><polyline points=\"10 17 15 12 10 7\"/><line x1=\"15\" y1=\"12\" x2=\"3\" y2=\"12\"/></svg>' +\n");
      out.write("                        'Login';\n");
      out.write("                    widget.appendChild(loginBtn);\n");
      out.write("                    widget.style.display = 'block';\n");
      out.write("\n");
      out.write("                } else {\n");
      out.write("                    /* ── Logged IN: show avatar trigger ── */\n");
      out.write("                    var firstName = (session.name || 'User').split(' ')[0];\n");
      out.write("                    var initials  = (session.name || 'U').slice(0, 2).toUpperCase();\n");
      out.write("                    var avatarUrl = 'https://ui-avatars.com/api/?name=' +\n");
      out.write("                                   encodeURIComponent(session.name || 'User') +\n");
      out.write("                                   '&background=d4a574&color=1a0f08&bold=true&size=64';\n");
      out.write("\n");
      out.write("                    var trigger = document.createElement('button');\n");
      out.write("                    trigger.className    = 'nav-avatar-trigger';\n");
      out.write("                    trigger.setAttribute('aria-haspopup', 'true');\n");
      out.write("                    trigger.setAttribute('aria-expanded', 'false');\n");
      out.write("                    trigger.setAttribute('aria-label', 'User menu');\n");
      out.write("                    trigger.innerHTML =\n");
      out.write("                        '<img src=\"' + avatarUrl + '\" alt=\"' + initials + '\" class=\"nav-avatar-img\" ' +\n");
      out.write("                             'onerror=\"this.style.display=\\'none\\'\">' +\n");
      out.write("                        '<span class=\"nav-avatar-name\">' + firstName + '</span>' +\n");
      out.write("                        '<svg class=\"nav-avatar-chevron\" width=\"14\" height=\"14\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2.5\" stroke-linecap=\"round\"><polyline points=\"6 9 12 15 18 9\"/></svg>';\n");
      out.write("\n");
      out.write("                    widget.appendChild(trigger);\n");
      out.write("                    widget.style.display = 'block';\n");
      out.write("\n");
      out.write("                    /* ── Build Dropdown ── */\n");
      out.write("                    function buildDropdown() {\n");
      out.write("                        var isAdmin = (session.role === 'admin');\n");
      out.write("                        var adminLink = isAdmin ? \n");
      out.write("                            '<a href=\"admin-dashboard.jsp\" class=\"nav-dropdown-item\" role=\"menuitem\" style=\"color:var(--color-primary);\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z\"/></svg>' +\n");
      out.write("                                'Admin Panel' +\n");
      out.write("                            '</a>' : '';\n");
      out.write("\n");
      out.write("                        var dd = document.createElement('div');\n");
      out.write("                        dd.className = 'nav-user-dropdown';\n");
      out.write("                        dd.setAttribute('role', 'menu');\n");
      out.write("                        dd.innerHTML =\n");
      out.write("                            '<div class=\"nav-dropdown-header\">' +\n");
      out.write("                                '<div class=\"nav-dropdown-uname\">' + (session.name || 'Traveller') + '</div>' +\n");
      out.write("                                '<div class=\"nav-dropdown-email\">' + (session.email || '') + '</div>' +\n");
      out.write("                            '</div>' +\n");
      out.write("                             adminLink +\n");
      out.write("                            '<a href=\"edit-profile.jsp\" class=\"nav-dropdown-item\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M20 21v-2a4 4 0 0 0-4-4H8a4 4 0 0 0-4 4v2\"/><circle cx=\"12\" cy=\"7\" r=\"4\"/></svg>' +\n");
      out.write("                                'Profile' +\n");
      out.write("                            '</a>' +\n");
      out.write("                            '<a href=\"booking?action=history\" class=\"nav-dropdown-item\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><rect x=\"3\" y=\"3\" width=\"7\" height=\"7\"/><rect x=\"14\" y=\"3\" width=\"7\" height=\"7\"/><rect x=\"14\" y=\"14\" width=\"7\" height=\"7\"/><rect x=\"3\" y=\"14\" width=\"7\" height=\"7\"/></svg>' +\n");
      out.write("                                'Dashboard' +\n");
      out.write("                            '</a>' +\n");
      out.write("                            '<a href=\"planner.jsp\" class=\"nav-dropdown-item\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M17 3a2 2 0 0 1 4 0v1H3V3a2 2 0 0 1 4 0\"/><rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\"/><line x1=\"8\" y1=\"10\" x2=\"16\" y2=\"10\"/><line x1=\"8\" y1=\"14\" x2=\"16\" y2=\"14\"/></svg>' +\n");
      out.write("                                'My Plans' +\n");
      out.write("                            '</a>' +\n");
      out.write("                            '<a href=\"booking\" class=\"nav-dropdown-item\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07A19.5 19.5 0 0 1 4.15 12a19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 3.06 1h3a2 2 0 0 1 2 1.72c.127.96.361 1.903.7 2.81a2 2 0 0 1-.45 2.11L7.09 8.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45c.907.339 1.85.573 2.81.7A2 2 0 0 1 21 16v.92z\"/></svg>' +\n");
      out.write("                                'My Bookings' +\n");
      out.write("                            '</a>' +\n");
      out.write("                            '<a href=\"settings.jsp\" class=\"nav-dropdown-item\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><circle cx=\"12\" cy=\"12\" r=\"3\"/><path d=\"M19.4 15a1.65 1.65 0 0 0 .33 1.82l.06.06a2 2 0 0 1 0 2.83 2 2 0 0 1-2.83 0l-.06-.06a1.65 1.65 0 0 0-1.82-.33 1.65 1.65 0 0 0-1 1.51V21a2 2 0 0 1-2 2 2 2 0 0 1-2-2v-.09A1.65 1.65 0 0 0 9 19.4a1.65 1.65 0 0 0-1.82.33l-.06.06a2 2 0 0 1-2.83 0 2 2 0 0 1 0-2.83l.06-.06a1.65 1.65 0 0 0 .33-1.82 1.65 1.65 0 0 0-1.51-1H3a2 2 0 0 1-2-2 2 2 0 0 1 2-2h.09A1.65 1.65 0 0 0 4.6 9a1.65 1.65 0 0 0-.33-1.82l-.06-.06a2 2 0 0 1 0-2.83 2 2 0 0 1 2.83 0l.06.06a1.65 1.65 0 0 0 1.82.33H9a1.65 1.65 0 0 0 1-1.51V3a2 2 0 0 1 2-2 2 2 0 0 1 2 2v.09a1.65 1.65 0 0 0 1 1.51 1.65 1.65 0 0 0 1.82-.33l.06-.06a2 2 0 0 1 2.83 0 2 2 0 0 1 0 2.83l-.06.06a1.65 1.65 0 0 0-.33 1.82V9a1.65 1.65 0 0 0 1.51 1H21a2 2 0 0 1 2 2 2 2 0 0 1-2 2h-.09a1.65 1.65 0 0 0-1.51 1z\"/></svg>' +\n");
      out.write("                                'Settings' +\n");
      out.write("                            '</a>' +\n");
      out.write("                            '<div class=\"nav-dropdown-divider\"></div>' +\n");
      out.write("                            '<button class=\"nav-dropdown-item logout-item\" id=\"navLogoutBtn\" role=\"menuitem\">' +\n");
      out.write("                                '<svg width=\"15\" height=\"15\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><path d=\"M9 21H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h4\"/><polyline points=\"16 17 21 12 16 7\"/><line x1=\"21\" y1=\"12\" x2=\"9\" y2=\"12\"/></svg>' +\n");
      out.write("                                'Log Out' +\n");
      out.write("                            '</button>';\n");
      out.write("\n");
      out.write("                        dd.querySelector('#navLogoutBtn').addEventListener('click', function () {\n");
      out.write("                            VoyastraAuth.logout();\n");
      out.write("                        });\n");
      out.write("                        return dd;\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ── Toggle dropdown ── */\n");
      out.write("                    function handleOutsideClick(e) {\n");
      out.write("                        if (dropdown && !widget.contains(e.target)) {\n");
      out.write("                            closeDropdown();\n");
      out.write("                        }\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    trigger.addEventListener('click', function (e) {\n");
      out.write("                        e.stopPropagation();\n");
      out.write("                        if (dropdown) {\n");
      out.write("                            closeDropdown();\n");
      out.write("                        } else {\n");
      out.write("                            dropdown = buildDropdown();\n");
      out.write("                            widget.appendChild(dropdown);\n");
      out.write("                            trigger.setAttribute('aria-expanded', 'true');\n");
      out.write("                            \n");
      out.write("                            // Add listener in next tick to avoid capturing current click\n");
      out.write("                            setTimeout(function() {\n");
      out.write("                                document.addEventListener('click', handleOutsideClick);\n");
      out.write("                            }, 0);\n");
      out.write("                        }\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    function closeDropdown() {\n");
      out.write("                        if (dropdown) {\n");
      out.write("                            dropdown.remove();\n");
      out.write("                            dropdown = null;\n");
      out.write("                            document.removeEventListener('click', handleOutsideClick);\n");
      out.write("                        }\n");
      out.write("                        trigger.setAttribute('aria-expanded', 'false');\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* Close on Escape */\n");
      out.write("                    document.addEventListener('keydown', function (e) {\n");
      out.write("                        if (e.key === 'Escape' && dropdown) closeDropdown();\n");
      out.write("                    });\n");
      out.write("                }\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            /* ── Initial render + live updates ────────────────── */\n");
      out.write("            renderAuthWidget();\n");
      out.write("            window.addEventListener('va:authChange', renderAuthWidget);\n");
      out.write("\n");
      out.write("            /* ── Active Nav Highlight ──────────────────────────── */\n");
      out.write("            var fullPath = window.location.pathname;\n");
      out.write("            var page = fullPath.split('/').pop() || 'index.jsp';\n");
      out.write("            if (!page.includes('.')) page += '.jsp'; // handle extensionless routers if any\n");
      out.write("            \n");
      out.write("            document.querySelectorAll('.nav-link').forEach(function (link) {\n");
      out.write("                var href = link.getAttribute('href');\n");
      out.write("                if (href === page || (page === 'index.jsp' && href === 'index.jsp')) {\n");
      out.write("                    link.classList.add('active');\n");
      out.write("                }\n");
      out.write("            });\n");
      out.write("\n");
      out.write("            /* ── Breadcrumbs ───────────────────────────────────── */\n");
      out.write("            var mainEl = document.querySelector('main');\n");
      out.write("            var skipBC = ['index.jsp', 'login.jsp', ''];\n");
      out.write("            if (mainEl && !skipBC.includes(currentPath)) {\n");
      out.write("                var pageName = currentPath.replace('.jsp', '');\n");
      out.write("                var formatted = pageName.split('-').map(function (w) {\n");
      out.write("                    return w.charAt(0).toUpperCase() + w.slice(1);\n");
      out.write("                }).join(' ');\n");
      out.write("                mainEl.insertAdjacentHTML('afterbegin',\n");
      out.write("                    '<div class=\"container relative z-20 slide-up\" style=\"padding-top:10px;margin-bottom:25px;animation-delay:0.1s;\">' +\n");
      out.write("                    '<nav aria-label=\"Breadcrumb\"><ol class=\"flex items-center gap-2 text-sm\" style=\"font-family:\\'Inter\\',sans-serif;\">' +\n");
      out.write("                    '<li><a href=\"index.jsp\" class=\"text-muted breadcrumb-link\" style=\"transition:color 0.2s;\">Home</a></li>' +\n");
      out.write("                    '<li class=\"text-muted\" style=\"opacity:0.5;\"><svg width=\"12\" height=\"12\" viewBox=\"0 0 24 24\" fill=\"none\" stroke=\"currentColor\" stroke-width=\"2\" stroke-linecap=\"round\"><polyline points=\"9 18 15 12 9 6\"/></svg></li>' +\n");
      out.write("                    '<li class=\"text-primary font-medium\" aria-current=\"page\">' + formatted + '</li>' +\n");
      out.write("                    '</ol></nav></div>');\n");
      out.write("            }\n");
      out.write("\n");
      out.write("        }); // DOMContentLoaded\n");
      out.write("    </script>\n");
      out.write('\n');
      out.write("<!-- ===== BACKGROUND SLIDER ===== -->\n");
