      out.write("\n");
      out.write("<!-- ===== PREMIUM PRELOADER (index.jsp â first visit only) ===== -->\n");
      out.write("<!--\n");
      out.write("     CRITICAL: Preloader div starts hidden (opacity:0, pointer-events:none).\n");
      out.write("     The inline script below immediately makes it visible only on first visit,\n");
      out.write("     BEFORE the rest of the DOM paints â avoiding any flash.\n");
      out.write("-->\n");
      out.write("<div id=\"voyastraPreloader\" style=\"\n");
      out.write("        display: flex;\n");
      out.write("        position: fixed;\n");
      out.write("        inset: 0;\n");
      out.write("        width: 100vw;\n");
      out.write("        height: 100vh;\n");
      out.write("        background: #ffffff;\n");
      out.write("        z-index: 9999999;\n");
      out.write("        align-items: center;\n");
      out.write("        justify-content: center;\n");
      out.write("        /* Start fully visible and opaque */\n");
      out.write("        opacity: 1;\n");
      out.write("        pointer-events: all;\">\n");
      out.write("\n");
      out.write("    <div style=\"display:flex; flex-direction:column; align-items:center; justify-content:center; gap:0;\">\n");
      out.write("        <!-- Animated infinity SVG path -->\n");
      out.write("        <svg style=\"width:300px; height:150px; display:block;\" viewBox=\"0 0 300 150\">\n");
      out.write("            <defs>\n");
      out.write("                <linearGradient id=\"preloaderGrad\" x1=\"0%\" y1=\"0%\" x2=\"100%\" y2=\"100%\">\n");
      out.write("                    <stop offset=\"0%\" stop-color=\"#4f46e5\" />\n");
      out.write("                    <stop offset=\"100%\" stop-color=\"#06b6d4\" />\n");
      out.write("                </linearGradient>\n");
      out.write("            </defs>\n");
      out.write("            <!-- Draw path -->\n");
      out.write("            <path class=\"preloader-infinity-path\"\n");
      out.write("                  d=\"M 150,75 C 200,15 300,15 300,75 C 300,135 200,135 150,75 C 100,15 0,15 0,75 C 0,135 100,135 150,75 Z\" />\n");
      out.write("            <!-- Airplane following path -->\n");
      out.write("            <path class=\"preloader-plane\" d=\"M -5 -4 L 8 0 L -5 4 L -2 0 Z\" fill=\"#0f0b08\" />\n");
      out.write("        </svg>\n");
      out.write("\n");
      out.write("        <!-- Dynamic font text -->\n");
      out.write("        <div class=\"preloader-text-dynamic\" style=\"color: #0f0b08; font-size: 1.5rem; letter-spacing: 0.2em; margin-top: 1rem; font-family: 'Inter', sans-serif; font-weight: 600;\">VOYASTRA</div>\n");
      out.write("    </div>\n");
      out.write("</div>\n");
      out.write("\n");
      out.write("<script>\n");
      out.write("    /* ââ Preloader: first-visit gate âââââââââââââââââââââââââââââââââââââ\n");
      out.write("       Runs synchronously right after the div is in the DOM.\n");
      out.write("       On RETURN visits â keep opacity 0, replace instantly with display none.\n");
      out.write("       On FIRST visit  â show the preloader, then hide after 3.5s minimum OR window.load.\n");
      out.write("    ââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââââ */\n");
      out.write("    (function () {\n");
      out.write("        var el  = document.getElementById('voyastraPreloader');\n");
      out.write("        var KEY = 'voyastra_visited';\n");
      out.write("\n");
      out.write("        if (!el) return;\n");
      out.write("\n");
      out.write("        if (sessionStorage.getItem(KEY)) {\n");
      out.write("            /* ââ Return visit: never show, hide synchronously before paint ââ */\n");
      out.write("            el.style.display = 'none';\n");
      out.write("            // Also removing it to clean up DOM\n");
      out.write("            if (el.parentNode) el.parentNode.removeChild(el);\n");
      out.write("            return;\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        /* ââ First visit of the session ââ */\n");
      out.write("        sessionStorage.setItem(KEY, '1');\n");
      out.write("\n");
      out.write("        var startTime   = Date.now();\n");
      out.write("        var MIN_MS      = 3500;   /* minimum visible time in ms */\n");
      out.write("        var hideApplied = false;\n");
      out.write("\n");
      out.write("        function applyHide() {\n");
      out.write("            if (hideApplied) return;\n");
      out.write("            hideApplied = true;\n");
      out.write("            // Add transition effect just before fading out\n");
      out.write("            el.style.transition = 'opacity 0.8s ease-in-out';\n");
      out.write("            el.style.opacity = '0';\n");
      out.write("            setTimeout(function () {\n");
      out.write("                el.style.display = 'none';\n");
      out.write("                if (el.parentNode) el.parentNode.removeChild(el);\n");
      out.write("            }, 820); /* matches transition duration */\n");
      out.write("        }\n");
      out.write("\n");
      out.write("        /* Wait for full page load */\n");
      out.write("        window.addEventListener('load', function () {\n");
      out.write("            var elapsed = Date.now() - startTime;\n");
      out.write("            var wait    = Math.max(0, MIN_MS - elapsed);\n");
      out.write("            setTimeout(applyHide, wait);\n");
      out.write("        });\n");
      out.write("\n");
      out.write("        /* Hard fallback: hide no matter what after 6 s */\n");
      out.write("        setTimeout(applyHide, 6000);\n");
      out.write("    })();\n");
      out.write("</script>\n");
      out.write("\n");
      out.write("\n");
