      out.write("            <script>\n");
      out.write("                document.addEventListener('DOMContentLoaded', () => {\n");
      out.write("                    const tabs = document.querySelectorAll('.sec-nav-item');\n");
      out.write("                    const contents = document.querySelectorAll('.booking-tab');\n");
      out.write("\n");
      out.write("                    tabs.forEach(tab => {\n");
      out.write("                        tab.addEventListener('click', () => {\n");
      out.write("                            const targetId = 'tab-' + tab.getAttribute('data-tab');\n");
      out.write("                            const targetElem = document.getElementById(targetId);\n");
      out.write("\n");
      out.write("                            if (targetElem) {\n");
      out.write("                                // Remove active class from all tabs\n");
      out.write("                                tabs.forEach(t => t.classList.remove('active'));\n");
      out.write("                                tab.classList.add('active');\n");
      out.write("\n");
      out.write("                                // Hide all contents\n");
      out.write("                                contents.forEach(c => c.style.display = 'none');\n");
      out.write("                                // Show target\n");
      out.write("                                targetElem.style.display = 'block';\n");
      out.write("                            } else {\n");
      out.write("                                // Fallback purely visual for missing tabs in prototype\n");
      out.write("                                tabs.forEach(t => t.classList.remove('active'));\n");
      out.write("                                tab.classList.add('active');\n");
      out.write("                            }\n");
      out.write("                        });\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("            </script>\n");
