      out.write("                <script>\n");
      out.write("                (function () {\n");
      out.write("                    'use strict';\n");
      out.write("\n");
      out.write("                    /* ââ Config ââ */\n");
      out.write("                    var AUTO_DELAY   = 4000;   // ms between auto-slides\n");
      out.write("                    var TRANSITION   = 600;    // ms CSS transition duration\n");
      out.write("\n");
      out.write("                    /* ââ DOM ââ */\n");
      out.write("                    var track    = document.getElementById('destTrack');\n");
      out.write("                    var viewport = document.getElementById('destViewport');\n");
      out.write("                    var prevBtn  = document.getElementById('destPrev');\n");
      out.write("                    var nextBtn  = document.getElementById('destNext');\n");
      out.write("                    var dotsEl   = document.getElementById('destDots');\n");
      out.write("                    var wrap     = document.getElementById('destCarouselWrap');\n");
      out.write("\n");
      out.write("                    if (!track || !viewport) return;\n");
      out.write("\n");
      out.write("                    /* ââ Determine cards-per-view ââ */\n");
      out.write("                    function getPerView() {\n");
      out.write("                        var w = window.innerWidth;\n");
      out.write("                        if (w >= 1100) return 4;\n");
      out.write("                        if (w >= 768)  return 3;\n");
      out.write("                        if (w >= 480)  return 2;\n");
      out.write("                        return 1;\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ State ââ */\n");
      out.write("                    var cards       = Array.prototype.slice.call(track.querySelectorAll('.dest-card'));\n");
      out.write("                    var totalCards  = cards.length;\n");
      out.write("                    var perView     = getPerView();\n");
      out.write("                    var current     = 0;       // logical index into original cards\n");
      out.write("                    var isAnimating = false;\n");
      out.write("                    var autoTimer   = null;\n");
      out.write("                    var clonesBefore, clonesAfter;\n");
      out.write("\n");
      out.write("                    /* ââ Build infinite clone track ââ */\n");
      out.write("                    function buildTrack() {\n");
      out.write("                        perView = getPerView();\n");
      out.write("\n");
      out.write("                        /* Remove old clones */\n");
      out.write("                        track.querySelectorAll('.dest-card-clone').forEach(function (el) { el.remove(); });\n");
      out.write("\n");
      out.write("                        /* Clone a full set before and after */\n");
      out.write("                        clonesBefore = totalCards;\n");
      out.write("                        clonesAfter  = totalCards;\n");
      out.write("\n");
      out.write("                        var frag = document.createDocumentFragment();\n");
      out.write("                        cards.forEach(function (c) {\n");
      out.write("                            var cl = c.cloneNode(true);\n");
      out.write("                            cl.classList.add('dest-card-clone');\n");
      out.write("                            frag.appendChild(cl);\n");
      out.write("                        });\n");
      out.write("                        track.insertBefore(frag, track.firstChild);   // clones BEFORE\n");
      out.write("\n");
      out.write("                        var frag2 = document.createDocumentFragment();\n");
      out.write("                        cards.forEach(function (c) {\n");
      out.write("                            var cl = c.cloneNode(true);\n");
      out.write("                            cl.classList.add('dest-card-clone');\n");
      out.write("                            frag2.appendChild(cl);\n");
      out.write("                        });\n");
      out.write("                        track.appendChild(frag2);                       // clones AFTER\n");
      out.write("\n");
      out.write("                        /* Attach 3D tilt to all cards in track */\n");
      out.write("                        Array.prototype.slice.call(track.querySelectorAll('.dest-card')).forEach(attach3D);\n");
      out.write("\n");
      out.write("                        /* Jump to real position silently */\n");
      out.write("                        jumpTo(current, false);\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Card width + gap ââ */\n");
      out.write("                    function cardWidth() {\n");
      out.write("                        var allCards = track.querySelectorAll('.dest-card');\n");
      out.write("                        if (!allCards.length) return 0;\n");
      out.write("                        var style = getComputedStyle(track);\n");
      out.write("                        var gap = parseFloat(style.gap) || 24;\n");
      out.write("                        return allCards[0].offsetWidth + gap;\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Translate to position (logical index) ââ */\n");
      out.write("                    function jumpTo(idx, animate) {\n");
      out.write("                        var cw         = cardWidth();\n");
      out.write("                        var realIdx    = idx + clonesBefore;   // offset by prepended clones\n");
      out.write("                        var translateX = -realIdx * cw;\n");
      out.write("\n");
      out.write("                        track.style.transition = animate\n");
      out.write("                            ? 'transform ' + TRANSITION + 'ms cubic-bezier(0.25,0.46,0.45,0.94)'\n");
      out.write("                            : 'none';\n");
      out.write("                        track.style.transform = 'translateX(' + translateX + 'px)';\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Infinite-loop bounce fix after transition ends ââ */\n");
      out.write("                    function onTransitionEnd() {\n");
      out.write("                        isAnimating = false;\n");
      out.write("                        if (current < 0) {\n");
      out.write("                            current += totalCards;\n");
      out.write("                            jumpTo(current, false);\n");
      out.write("                        } else if (current >= totalCards) {\n");
      out.write("                            current -= totalCards;\n");
      out.write("                            jumpTo(current, false);\n");
      out.write("                        }\n");
      out.write("                        updateDots();\n");
      out.write("                    }\n");
      out.write("                    track.addEventListener('transitionend', onTransitionEnd);\n");
      out.write("\n");
      out.write("                    /* ââ Go to card ââ */\n");
      out.write("                    function goTo(idx, animate) {\n");
      out.write("                        if (animate && isAnimating) return;\n");
      out.write("                        if (animate) isAnimating = true;\n");
      out.write("                        current = idx;\n");
      out.write("                        jumpTo(current, animate !== false);\n");
      out.write("                        if (!animate) updateDots();\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    function goNext() {\n");
      out.write("                        goTo(current + 1, true);\n");
      out.write("                        resetAuto();\n");
      out.write("                    }\n");
      out.write("                    function goPrev() {\n");
      out.write("                        goTo(current - 1, true);\n");
      out.write("                        resetAuto();\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Dots ââ */\n");
      out.write("                    function buildDots() {\n");
      out.write("                        dotsEl.innerHTML = '';\n");
      out.write("                        var pages = Math.ceil(totalCards / perView);\n");
      out.write("                        for (var i = 0; i < pages; i++) {\n");
      out.write("                            (function (idx) {\n");
      out.write("                                var btn = document.createElement('button');\n");
      out.write("                                btn.className = 'dest-dot' + (idx === 0 ? ' active' : '');\n");
      out.write("                                btn.setAttribute('aria-label', 'Go to slide ' + (idx + 1));\n");
      out.write("                                btn.addEventListener('click', function () {\n");
      out.write("                                    goTo(idx * perView, true);\n");
      out.write("                                    resetAuto();\n");
      out.write("                                });\n");
      out.write("                                dotsEl.appendChild(btn);\n");
      out.write("                            })(i);\n");
      out.write("                        }\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    function updateDots() {\n");
      out.write("                        var idx = ((current % totalCards) + totalCards) % totalCards;\n");
      out.write("                        var activePage = Math.floor(idx / perView);\n");
      out.write("                        Array.prototype.slice.call(dotsEl.querySelectorAll('.dest-dot')).forEach(function (d, i) {\n");
      out.write("                            d.classList.toggle('active', i === activePage);\n");
      out.write("                        });\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Auto rotation ââ */\n");
      out.write("                    function startAuto() {\n");
      out.write("                        autoTimer = setInterval(goNext, AUTO_DELAY);\n");
      out.write("                    }\n");
      out.write("                    function stopAuto() {\n");
      out.write("                        clearInterval(autoTimer);\n");
      out.write("                    }\n");
      out.write("                    function resetAuto() {\n");
      out.write("                        stopAuto();\n");
      out.write("                        startAuto();\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Pause on hover ââ */\n");
      out.write("                    wrap.addEventListener('mouseenter', stopAuto);\n");
      out.write("                    wrap.addEventListener('mouseleave', startAuto);\n");
      out.write("\n");
      out.write("                    /* ââ Arrow controls ââ */\n");
      out.write("                    prevBtn && prevBtn.addEventListener('click', goPrev);\n");
      out.write("                    nextBtn && nextBtn.addEventListener('click', goNext);\n");
      out.write("\n");
      out.write("                    /* ââ Touch/swipe support ââ */\n");
      out.write("                    var touchStartX = 0;\n");
      out.write("                    viewport.addEventListener('touchstart', function (e) {\n");
      out.write("                        touchStartX = e.touches[0].clientX;\n");
      out.write("                        stopAuto();\n");
      out.write("                    }, { passive: true });\n");
      out.write("                    viewport.addEventListener('touchend', function (e) {\n");
      out.write("                        var dx = e.changedTouches[0].clientX - touchStartX;\n");
      out.write("                        if (Math.abs(dx) > 40) {\n");
      out.write("                            dx < 0 ? goNext() : goPrev();\n");
      out.write("                        }\n");
      out.write("                        startAuto();\n");
      out.write("                    }, { passive: true });\n");
      out.write("\n");
      out.write("                    /* ââ 3D Tilt effect ââ */\n");
      out.write("                    function attach3D(card) {\n");
      out.write("                        card.addEventListener('mousemove', function (e) {\n");
      out.write("                            var rect   = card.getBoundingClientRect();\n");
      out.write("                            var cx     = rect.left + rect.width / 2;\n");
      out.write("                            var cy     = rect.top  + rect.height / 2;\n");
      out.write("                            var dx     = (e.clientX - cx) / (rect.width  / 2);  // -1 â¦ 1\n");
      out.write("                            var dy     = (e.clientY - cy) / (rect.height / 2);  // -1 â¦ 1\n");
      out.write("                            var rotY   =  dx * 10;   // max Â±10Â°\n");
      out.write("                            var rotX   = -dy *  7;   // max  Â±7Â°\n");
      out.write("                            card.style.transform =\n");
      out.write("                                'perspective(1000px) rotateX(' + rotX + 'deg) rotateY(' + rotY + 'deg) scale(1.04)';\n");
      out.write("                        });\n");
      out.write("                        card.addEventListener('mouseleave', function () {\n");
      out.write("                            card.style.transform =\n");
      out.write("                                'perspective(1000px) rotateX(0deg) rotateY(0deg) scale(1)';\n");
      out.write("                        });\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* ââ Resize handler ââ */\n");
      out.write("                    var resizeTimer;\n");
      out.write("                    window.addEventListener('resize', function () {\n");
      out.write("                        clearTimeout(resizeTimer);\n");
      out.write("                        resizeTimer = setTimeout(function () {\n");
      out.write("                            stopAuto();\n");
      out.write("                            buildTrack();\n");
      out.write("                            buildDots();\n");
      out.write("                            startAuto();\n");
      out.write("                        }, 180);\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    /* ââ Init ââ */\n");
      out.write("                    buildTrack();\n");
      out.write("                    buildDots();\n");
      out.write("                    startAuto();\n");
      out.write("\n");
      out.write("                })();\n");
      out.write("                </script>\n");
      out.write("\n");
      out.write("            </section>\n");
      out.write("\n");
