      out.write("                    '--color-muted': 'rgba(215,200,175,0.6)',\n");
      out.write("                    '--color-surface': 'rgba(185,168,140,0.06)', '--color-border': 'rgba(210,192,165,0.16)',\n");
      out.write("                    '--text-heading': '#f8f5f0', '--text-body': 'rgba(238,228,215,0.7)'\n");
      out.write("                },\n");
      out.write("                // 11 â Ooty (pine forest dark + mist white)\n");
      out.write("                {\n");
      out.write("                    '--color-primary': '#78b890', '--color-accent': '#286848',\n");
      out.write("                    '--color-muted': 'rgba(128,185,148,0.6)',\n");
      out.write("                    '--color-surface': 'rgba(75,148,105,0.06)', '--color-border': 'rgba(105,178,130,0.16)',\n");
      out.write("                    '--text-heading': '#eef4f0', '--text-body': 'rgba(195,228,208,0.7)'\n");
      out.write("                },\n");
      out.write("            ];\n");
      out.write("\n");
      out.write("            /* Luminosity classifier â true = light BG photo needs dark text */\n");
      out.write("            const themesAreLight = [\n");
      out.write("                true, false, false, false, false, false, false, false, false, true, true, true\n");
      out.write("            ];\n");
      out.write("\n");
      out.write("            /* Darker primary/accent variants for when theme is light */\n");
      out.write("            const lightThemeDark = {\n");
      out.write("                0: { primary: '#2d6e98', accent: '#1a4a6a' },  // Taj Mahal\n");
      out.write("                9: { primary: '#3a5830', accent: '#223520' },  // Darjeeling\n");
      out.write("                10: { primary: '#7a5830', accent: '#4a3010' },  // Rann of Kutch\n");
      out.write("                11: { primary: '#1a5c38', accent: '#0a3820' },  // Ooty\n");
      out.write("            };\n");
      out.write("\n");
      out.write("            function applyTheme(index) {\n");
      out.write("                const t = themes[index] || themes[0];\n");
      out.write("                const root = document.documentElement;\n");
      out.write("                const isLight = themesAreLight[index] || false;\n");
      out.write("\n");
      out.write("                // Ensure class is set immediately for all rules\n");
      out.write("                document.body.classList.toggle('theme-light', isLight);\n");
      out.write("\n");
      out.write("                // Write all CSS custom properties from theme object\n");
      out.write("                Object.entries(t).forEach(([k, v]) => root.style.setProperty(k, v));\n");
      out.write("\n");
      out.write("                let primary, accent, muted, heading, border, surface, textBody;\n");
      out.write("                if (isLight) {\n");
      out.write("                    const dk = lightThemeDark[index];\n");
      out.write("                    primary = dk.primary;\n");
      out.write("                    accent = dk.accent;\n");
      out.write("                    muted = 'rgba(40,30,18,0.55)';\n");
      out.write("                    heading = '#1a1612';\n");
      out.write("                    textBody = 'rgba(30,22,12,0.72)';\n");
      out.write("                    surface = 'rgba(15,10,5,0.06)';\n");
      out.write("                    border = 'rgba(20,14,6,0.15)';\n");
      out.write("                    root.style.setProperty('--color-primary', primary);\n");
      out.write("                    root.style.setProperty('--color-accent', accent);\n");
      out.write("                    root.style.setProperty('--color-muted', muted);\n");
      out.write("                    root.style.setProperty('--text-heading', heading);\n");
      out.write("                    root.style.setProperty('--text-body', textBody);\n");
      out.write("                    root.style.setProperty('--color-surface', surface);\n");
      out.write("                    root.style.setProperty('--color-border', border);\n");
      out.write("                    document.querySelectorAll('.bg-slide').forEach(s => s.style.filter = 'brightness(0.78)');\n");
      out.write("                } else {\n");
      out.write("                    primary = t['--color-primary'];\n");
      out.write("                    accent = t['--color-accent'];\n");
      out.write("                    muted = t['--color-muted'];\n");
      out.write("                    heading = t['--text-heading'];\n");
      out.write("                    textBody = t['--text-body'];\n");
      out.write("                    surface = t['--color-surface'];\n");
      out.write("                    border = t['--color-border'];\n");
      out.write("                    document.querySelectorAll('.bg-slide').forEach(s => s.style.filter = 'brightness(0.40)');\n");
      out.write("                }\n");
      out.write("\n");
      out.write("                document.querySelectorAll('.bg-dot.active').forEach(d => d.style.boxShadow = '0 0 10px ' + primary);\n");
      out.write("                document.querySelectorAll('.stat-num').forEach(el => el.style.color = primary);\n");
      out.write("                document.querySelectorAll('.section-eyebrow').forEach(el => el.style.color = accent);\n");
      out.write("                document.querySelectorAll('.badge').forEach(el => { el.style.borderColor = border; el.style.color = muted; });\n");
      out.write("\n");
      out.write("                document.querySelectorAll('.btn-glow-primary').forEach(el => {\n");
      out.write("                    if (isLight) {\n");
      out.write("                        el.style.background = accent;\n");
      out.write("                        el.style.color = '#fff';\n");
      out.write("                    } else {\n");
      out.write("                        el.style.background = heading;\n");
      out.write("                        el.style.color = '#111';\n");
      out.write("                    }\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                document.querySelectorAll('.btn-glow-ghost').forEach(el => { el.style.borderColor = border; el.style.color = heading; });\n");
      out.write("                document.querySelectorAll('.city-item').forEach(el => el.style.backgroundImage = 'linear-gradient(to right, ' + heading + ', transparent)');\n");
      out.write("                document.querySelectorAll('.nav-link, .nav-brand').forEach(el => el.style.color = heading);\n");
      out.write("\n");
      out.write("                const navbar = document.querySelector('.navbar');\n");
      out.write("                if (navbar) {\n");
      out.write("                    navbar.style.background = isLight ? 'rgba(255,255,255,0.22)' : 'rgba(10,8,5,0.35)';\n");
      out.write("                    navbar.style.borderBottom = '1px solid ' + border;\n");
      out.write("                }\n");
      out.write("            }\n");
      out.write("\n");
      out.write("            document.addEventListener('DOMContentLoaded', () => {\n");
      out.write("                // 1. MUST APPLY THEME BEFORE FIRST PAINT\n");
      out.write("                applyTheme(0);\n");
      out.write("\n");
      out.write("                /* --- Custom Cursor --- */\n");
      out.write("                const cursorDot = document.getElementById('cursorDot');\n");
      out.write("                const cursorOutline = document.getElementById('cursorOutline');\n");
      out.write("\n");
      out.write("                window.addEventListener('mousemove', (e) => {\n");
      out.write("                    const posX = e.clientX;\n");
      out.write("                    const posY = e.clientY;\n");
      out.write("\n");
      out.write("                    cursorDot.style.left = posX + 'px';\n");
      out.write("                    cursorDot.style.top = posY + 'px';\n");
      out.write("\n");
      out.write("                    // Add a slight delay to the outline using JS animation\n");
      out.write("                    cursorOutline.animate({\n");
      out.write("                        left: posX + 'px',\n");
      out.write("                        top: posY + 'px'\n");
      out.write("                    }, { duration: 500, fill: \"forwards\" });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                // Enlarge outline on hoverable elements\n");
      out.write("                const hoverables = document.querySelectorAll('a, button, .dest-item, .tilt-card');\n");
      out.write("                hoverables.forEach(el => {\n");
      out.write("                    el.addEventListener('mouseenter', () => {\n");
      out.write("                        cursorOutline.style.width = '60px';\n");
      out.write("                        cursorOutline.style.height = '60px';\n");
      out.write("                        cursorOutline.style.backgroundColor = 'rgba(79, 70, 229, 0.2)';\n");
      out.write("                    });\n");
      out.write("                    el.addEventListener('mouseleave', () => {\n");
      out.write("                        cursorOutline.style.width = '40px';\n");
      out.write("                        cursorOutline.style.height = '40px';\n");
      out.write("                        cursorOutline.style.backgroundColor = 'transparent';\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                /* --- Slot Machine Rotator --- */\n");
      out.write("                const track = document.getElementById('rotatorTrack');\n");
      out.write("                const words = track.children;\n");
      out.write("                const wordHeight = 1.2; // em\n");
      out.write("                let currentWord = 0;\n");
      out.write("\n");
      out.write("                setInterval(() => {\n");
      out.write("                    currentWord++;\n");
      out.write("                    track.style.transition = 'transform 0.6s cubic-bezier(0.68, -0.55, 0.265, 1.55)';\n");
      out.write("                    track.style.transform = 'translateY(-' + (currentWord * wordHeight) + 'em)';\n");
      out.write("\n");
      out.write("                    // Reset when reaching the clone\n");
      out.write("                    if (currentWord === words.length - 1) {\n");
      out.write("                        setTimeout(() => {\n");
      out.write("                            track.style.transition = 'none';\n");
      out.write("                            currentWord = 0;\n");
      out.write("                            track.style.transform = 'translateY(0)';\n");
      out.write("                        }, 600);\n");
      out.write("                    }\n");
      out.write("                }, 2400);\n");
      out.write("\n");
      out.write("                /* --- Background Slider & Hover Logic --- */\n");
      out.write("                const bgSlides = document.querySelectorAll('.bg-slide');\n");
      out.write("                const bgDots = document.querySelectorAll('.bg-dot');\n");
      out.write("                let bgIndex = 0;\n");
      out.write("                let bgInterval;\n");
      out.write("\n");
      out.write("                function setBg(index) {\n");
      out.write("                    bgSlides.forEach(s => s.classList.remove('active'));\n");
      out.write("                    bgDots.forEach(d => d.classList.remove('active'));\n");
      out.write("\n");
      out.write("                    bgSlides[index].classList.add('active');\n");
      out.write("                    bgDots[index].classList.add('active');\n");
      out.write("                    bgIndex = index;\n");
      out.write("\n");
      out.write("                    // Apply theme 100ms after bg starts fading so colors follow\n");
      out.write("                    setTimeout(() => applyTheme(index), 100);\n");
      out.write("                }\n");
      out.write("\n");
      out.write("                function startBgInterval() {\n");
      out.write("                    clearInterval(bgInterval);\n");
      out.write("                    bgInterval = setInterval(() => {\n");
      out.write("                        let nextIndex = (bgIndex + 1) % bgSlides.length;\n");
      out.write("                        setBg(nextIndex);\n");
      out.write("                    }, 5000);\n");
      out.write("                }\n");
      out.write("\n");
      out.write("                // Ensure first interval run waits logic\n");
      out.write("                startBgInterval();\n");
      out.write("\n");
      out.write("                // Dot clicks\n");
      out.write("                bgDots.forEach((dot, i) => {\n");
      out.write("                    dot.addEventListener('click', () => {\n");
      out.write("                        setBg(i);\n");
      out.write("                        startBgInterval();\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                // Destination Grid Hover â activates specific BG + theme\n");
      out.write("                const destItems = document.querySelectorAll('.dest-item');\n");
      out.write("                destItems.forEach(item => {\n");
      out.write("                    item.addEventListener('mouseenter', () => {\n");
      out.write("                        const idx = parseInt(item.getAttribute('data-bg-index'));\n");
      out.write("                        if (!isNaN(idx)) {\n");
      out.write("                            setBg(idx);\n");
      out.write("                            clearInterval(bgInterval);\n");
      out.write("                        }\n");
      out.write("                    });\n");
      out.write("                    item.addEventListener('mouseleave', () => {\n");
      out.write("                        startBgInterval();\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                /* --- Mouse Parallax --- */\n");
      out.write("                const parallaxWrappers = document.querySelectorAll('.parallax-wrapper');\n");
      out.write("                window.addEventListener('mousemove', (e) => {\n");
      out.write("                    const x = (e.clientX / window.innerWidth - 0.5) * 2; // -1 to 1\n");
      out.write("                    const y = (e.clientY / window.innerHeight - 0.5) * 2; // -1 to 1\n");
      out.write("\n");
      out.write("                    parallaxWrappers.forEach(wrapper => {\n");
      out.write("                        const elements = wrapper.querySelectorAll('.parallax-bg');\n");
      out.write("                        elements.forEach(el => {\n");
      out.write("                            const speed = parseFloat(el.getAttribute('data-speed'));\n");
      out.write("                            const xOffset = x * 100 * speed;\n");
      out.write("                            const yOffset = y * 100 * speed;\n");
      out.write("                            el.style.transform = 'translate(' + xOffset + 'px, ' + yOffset + 'px)';\n");
      out.write("                        });\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    // Subtly move the background slides in reverse\n");
      out.write("                    bgSlides.forEach(slide => {\n");
      out.write("                        if (slide.classList.contains('active')) {\n");
      out.write("                            const bgX = x * -20;\n");
      out.write("                            const bgY = y * -20;\n");
      out.write("                            slide.style.transform = 'translate(' + bgX + 'px, ' + bgY + 'px) scale(1.05)';\n");
      out.write("                        }\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                /* --- Scroll Fade & Vertical Progress Line --- */\n");
      out.write("                const scrollFades = document.querySelectorAll('.scroll-fade');\n");
      out.write("                const scrollProgress = document.getElementById('scrollProgress');\n");
      out.write("\n");
      out.write("                function checkScroll() {\n");
      out.write("                    const triggerBottom = window.innerHeight * 0.85;\n");
      out.write("                    scrollFades.forEach(el => {\n");
      out.write("                        const top = el.getBoundingClientRect().top;\n");
      out.write("                        if (top < triggerBottom) {\n");
      out.write("                            el.classList.add('visible');\n");
      out.write("                        }\n");
      out.write("                    });\n");
      out.write("                }\n");
      out.write("\n");
      out.write("                checkScroll();\n");
      out.write("\n");
      out.write("                window.addEventListener('scroll', () => {\n");
      out.write("                    checkScroll();\n");
      out.write("\n");
      out.write("                    // Progress Line\n");
      out.write("                    const scrollPx = document.documentElement.scrollTop;\n");
      out.write("                    const winHeightPx = document.documentElement.scrollHeight - document.documentElement.clientHeight;\n");
      out.write("                    const scrolled = (scrollPx / winHeightPx * 100) + '%';\n");
      out.write("                    if (scrollProgress) scrollProgress.style.height = scrolled;\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                /* --- 3D Tilt Effect on Cards --- */\n");
      out.write("                const tiltElements = document.querySelectorAll('.tilt-card');\n");
      out.write("                tiltElements.forEach(el => {\n");
      out.write("                    const restingState = el.style.transform || 'rotateX(0deg) rotateY(0deg) scale3d(1, 1, 1)';\n");
      out.write("                    el.setAttribute('data-resting', restingState);\n");
      out.write("\n");
      out.write("                    el.addEventListener('mousemove', (e) => {\n");
      out.write("                        const rect = el.getBoundingClientRect();\n");
      out.write("                        const posX = e.clientX - rect.left;\n");
      out.write("                        const posY = e.clientY - rect.top;\n");
      out.write("                        const centerX = rect.width / 2;\n");
      out.write("                        const centerY = rect.height / 2;\n");
      out.write("\n");
      out.write("                        const rotateX = ((posY - centerY) / centerY) * -12;\n");
      out.write("                        const rotateY = ((posX - centerX) / centerX) * 12;\n");
      out.write("\n");
      out.write("                        el.style.transform = 'rotateX(' + rotateX + 'deg) rotateY(' + rotateY + 'deg) scale3d(1.05, 1.05, 1.05)';\n");
      out.write("                        el.style.transition = 'none';\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    el.addEventListener('mouseleave', () => {\n");
      out.write("                        el.style.transform = el.getAttribute('data-resting');\n");
      out.write("                        el.style.transition = 'transform 0.6s cubic-bezier(0.25, 0.46, 0.45, 0.94)';\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    el.addEventListener('mouseenter', () => {\n");
      out.write("                        el.style.transition = 'transform 0.1s ease-out';\n");
      out.write("                    });\n");
      out.write("                });\n");
      out.write("\n");
      out.write("                /* ======== PLAN CARDS PROXIMITY EDGE SCROLL ======== */\n");
      out.write("                (function () {\n");
      out.write("                    const outer = document.querySelector('.plan-scroll-outer');\n");
      out.write("                    const inner = document.getElementById('planScrollInner');\n");
      out.write("                    if (!outer || !inner) return;\n");
      out.write("\n");
      out.write("                    const ZONE = 120;   // px from each edge\n");
      out.write("                    const BASE_RATE = 1;     // normal speed (1x at 58s/loop)\n");
      out.write("                    const MAX_RATE = 2.636; // 58s / 22s = 2.636x at max edge speed\n");
      out.write("                    const LERP_T = 0.08;  // lerp factor per rAF frame\n");
      out.write("\n");
      out.write("                    let targetRate = BASE_RATE;\n");
      out.write("                    let currentRate = BASE_RATE;\n");
      out.write("                    let rafId = null;\n");
      out.write("\n");
      out.write("                    /* Grab the running CSS animation object */\n");
      out.write("                    function getAnim() {\n");
      out.write("                        const anims = inner.getAnimations ? inner.getAnimations() : [];\n");
      out.write("                        return anims[0] || null;\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    function lerp(a, b, t) { return a + (b - a) * t; }\n");
      out.write("\n");
      out.write("                    /* rAF loop â only lerps playbackRate, never restarts the animation */\n");
      out.write("                    function tick() {\n");
      out.write("                        currentRate = lerp(currentRate, targetRate, LERP_T);\n");
      out.write("                        if (Math.abs(currentRate - targetRate) < 0.01) currentRate = targetRate;\n");
      out.write("\n");
      out.write("                        const anim = getAnim();\n");
      out.write("                        if (anim) anim.playbackRate = currentRate;\n");
      out.write("\n");
      out.write("                        if (Math.abs(currentRate - targetRate) > 0.01) {\n");
      out.write("                            rafId = requestAnimationFrame(tick);\n");
      out.write("                        } else {\n");
      out.write("                            rafId = null;\n");
      out.write("                        }\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    function startLerp() {\n");
      out.write("                        if (!rafId) rafId = requestAnimationFrame(tick);\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    /* Mousemove â calculate which zone the cursor is in */\n");
      out.write("                    outer.addEventListener('mousemove', function (e) {\n");
      out.write("                        const rect = outer.getBoundingClientRect();\n");
      out.write("                        const posX = e.clientX - rect.left;\n");
      out.write("                        const width = rect.width;\n");
      out.write("\n");
      out.write("                        if (posX < ZONE) {\n");
      out.write("                            // Left edge zone â reverse + speed up\n");
      out.write("                            const t = 1 - posX / ZONE;              // 0..1 (0 = zone edge, 1 = far left)\n");
      out.write("                            targetRate = -lerp(BASE_RATE, MAX_RATE, t);\n");
      out.write("                        } else if (posX > width - ZONE) {\n");
      out.write("                            // Right edge zone â forward + speed up\n");
      out.write("                            const t = 1 - (width - posX) / ZONE;   // 0..1 (0 = zone edge, 1 = far right)\n");
      out.write("                            targetRate = lerp(BASE_RATE, MAX_RATE, t);\n");
      out.write("                        } else {\n");
      out.write("                            // Centre â normal forward speed\n");
      out.write("                            targetRate = BASE_RATE;\n");
      out.write("                        }\n");
      out.write("\n");
      out.write("                        startLerp();\n");
      out.write("                    });\n");
      out.write("\n");
      out.write("                    /* Mouse leaves â restore normal forward speed smoothly */\n");
      out.write("                    outer.addEventListener('mouseleave', function () {\n");
      out.write("                        targetRate = BASE_RATE;\n");
      out.write("                        startLerp();\n");
      out.write("                    });\n");
      out.write("                })();\n");
      out.write("\n");
      out.write("                /* ======== DARK / LIGHT MODE TOGGLE ======== */\n");
      out.write("                (function () {\n");
      out.write("                    const btn = document.getElementById('themeToggle');\n");
      out.write("                    const html = document.documentElement;\n");
      out.write("\n");
      out.write("                    // If no manual preference yet, detect system preference\n");
      out.write("                    if (!html.getAttribute('data-theme')) {\n");
      out.write("                        const sys = window.matchMedia('(prefers-color-scheme: dark)').matches ? 'dark' : 'light';\n");
      out.write("                        html.setAttribute('data-theme', sys);\n");
      out.write("                    }\n");
      out.write("\n");
      out.write("                    if (btn) {\n");
      out.write("                        btn.addEventListener('click', function () {\n");
      out.write("                            const current = html.getAttribute('data-theme');\n");
      out.write("                            const next = current === 'dark' ? 'light' : 'dark';\n");
      out.write("                            html.setAttribute('data-theme', next);\n");
      out.write("                            localStorage.setItem('theme', next);\n");
      out.write("                        });\n");
      out.write("                    }\n");
      out.write("                })();\n");
      out.write("\n");
      out.write("            });\n");
      out.write("        </script>\n");
      out.write("\n");
      out.write("        <!-- ===== INTELLIGENT SEARCH MODAL ===== -->\n");
      out.write("        <div id=\"intelligentSearchModal\" class=\"search-dropdown hidden\">\n");
      out.write("            <div class=\"dropdown-header\">\n");
      out.write("                <input type=\"text\" id=\"intelligentSearchInput\" class=\"search-dropdown-input\" placeholder=\"Search city or airport...\" autocomplete=\"off\">\n");
      out.write("            </div>\n");
      out.write("            <div class=\"dropdown-body\">\n");
      out.write("                <!-- Recent searches section -->\n");
      out.write("                <div id=\"searchRecentSection\" class=\"dropdown-section hidden\">\n");
      out.write("                    <div class=\"section-title\">Recent Searches</div>\n");
      out.write("                    <ul class=\"suggestion-list\" id=\"searchRecentList\"></ul>\n");
      out.write("                </div>\n");
      out.write("                <!-- Popular destinations section -->\n");
      out.write("                <div id=\"searchPopularSection\" class=\"dropdown-section\">\n");
      out.write("                    <div class=\"section-title\">Popular Destinations</div>\n");
      out.write("                    <ul class=\"suggestion-list\" id=\"searchPopularList\"></ul>\n");
      out.write("                </div>\n");
      out.write("                <!-- Auto-suggestions (Filtered) -->\n");
      out.write("                <div id=\"searchSuggestionsSection\" class=\"dropdown-section hidden\">\n");
      out.write("                    <ul class=\"suggestion-list\" id=\"searchSuggestionsList\"></ul>\n");
      out.write("                </div>\n");
      out.write("            </div>\n");
      out.write("        </div>\n");
      out.write("\n");
      out.write("        <script>\n");
      out.write("            document.addEventListener('DOMContentLoaded', () => {\n");
      out.write("                // DB of Indian Cities/Airports\n");
      out.write("                const SEARCH_DB = [\n");
      out.write("                    { city: 'Delhi', airport: 'DEL, Indira Gandhi Intl', icon: 'M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z' },\n");
