      out.write("                    { city: 'Jaipur', airport: 'JAI, Jaipur Intl', icon: 'M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z' },\n");
      out.write("                    { city: 'Udaipur', airport: 'UDR, Maharana Pratap', icon: 'M21 10c0 7-9 13-9 13s-9-6-9-13a9 9 0 0 1 18 0z' },\n");
