      out.write("                const popularSection = document.getElementById('searchPopularSection');\n");
      out.write("                const popularList = document.getElementById('searchPopularList');\n");
      out.write("                const suggestionsSection = document.getElementById('searchSuggestionsSection');\n");
      out.write("                const suggestionsList = document.getElementById('searchSuggestionsList');\n");
      out.write("                \n");
      out.write("                let activeSearchField = null;\n");
      out.write("\n");
      out.write("                // Create a list item HTML string\n");
